/*
 * STOCK CONFIG — EGX Deep Analyst
 * Yahoo EGX ticker format: TICKER.CA
 * Fetch Matrix: 15m→60d, 1H→60d, 1W→5y. 4H synthesized from 1H.
 */
const STOCKS = [
  { ticker: 'SKPC',  name: 'Sidi Kerir Petrochemicals' },
  { ticker: 'ICFC',  name: 'International Co For Investment & Development' },
  { ticker: 'IFAP',  name: 'International Agricultural Products' },
  { ticker: 'ISMQ',  name: 'Iron And Steel for Mines and Quarries' },
  { ticker: 'ZMID',  name: 'Zahraa El Maadi Investment & Development' }
];

const FETCH_MATRIX = [
  { id: '15m',  interval: '15m',  range: '60d',  label: '15-Minute Entry' },
  { id: '1H',   interval: '60m',  range: '60d',  label: '1-Hour Swing' },
  { id: '1W',   interval: '1wk',  range: '5y',   label: 'Weekly Deep' }
];

const runDate = new Date().toISOString().split('T')[0];
return [{ json: { stocks: STOCKS, fetchMatrix: FETCH_MATRIX, runDate } }];

/*
 * YAHOO FINANCE DEFENSIVE FETCHER v4
 * Architecture: sequential per stock, 3 TFs, 2s delays, 3 retries
 * Data Healer: MOC filter, grid inject, piastre fix, 4H synthesis
 */
if ($input.all()[0]?.json?._skip) return $input.all();

const sleep = ms => new Promise(r => setTimeout(r, ms));
const httpReq = this.helpers.httpRequest;
const config = $input.all()[0].json;
const { stocks, fetchMatrix, runDate } = config;

const YAHOO_BASE = 'https://query1.finance.yahoo.com/v8/finance/chart';
const YAHOO_HEADERS = {
  'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
  'Accept': 'application/json'
};

const CAIRO_OFFSET_MS = 2 * 60 * 60 * 1000;
function toCairoHour(unixSec) {
  const d = new Date((unixSec * 1000) + CAIRO_OFFSET_MS);
  return d.getUTCHours();
}
function toCairoDate(unixSec) {
  const d = new Date((unixSec * 1000) + CAIRO_OFFSET_MS);
  return d.toISOString().split('T')[0];
}

async function fetchYahoo(ticker, interval, range, maxRetries) {
  maxRetries = maxRetries || 3;
  const url = YAHOO_BASE + '/' + ticker + '.CA?interval=' + interval + '&range=' + range;
  for (let attempt = 0; attempt < maxRetries; attempt++) {
    try {
      const resp = await httpReq({
        method: 'GET', url,
        headers: YAHOO_HEADERS,
        returnFullResponse: true, ignoreHttpStatusErrors: true, timeout: 20000
      });
      if (resp.statusCode === 200) {
        const body = typeof resp.body === 'string' ? JSON.parse(resp.body) : resp.body;
        return { ok: true, data: body };
      }
      if (resp.statusCode === 404) return { ok: false, err: 'Yahoo 404: ' + ticker + '.CA not found' };
      if (resp.statusCode === 401 || resp.statusCode === 403) {
        await sleep(5000 * (attempt + 1));
        continue;
      }
      if (attempt === maxRetries - 1) return { ok: false, err: 'Yahoo HTTP ' + resp.statusCode };
    } catch (e) {
      if (attempt === maxRetries - 1) return { ok: false, err: 'Yahoo error: ' + e.message };
    }
    await sleep(2000 * Math.pow(2, attempt));
  }
  return { ok: false, err: 'Max retries exceeded' };
}

function extractOHLCV(yahooData) {
  const result = yahooData?.chart?.result?.[0];
  if (!result?.timestamp) return null;
  const ts = result.timestamp;
  const q = result.indicators?.quote?.[0];
  if (!q) return null;
  return {
    timestamps: ts,
    opens:   ts.map((_, i) => q.open?.[i] ?? null),
    highs:   ts.map((_, i) => q.high?.[i] ?? null),
    lows:    ts.map((_, i) => q.low?.[i] ?? null),
    closes:  ts.map((_, i) => q.close?.[i] ?? null),
    volumes: ts.map((_, i) => q.volume?.[i] ?? 0)
  };
}

function fixPiastreAnomaly(closes) {
  if (closes.length < 10) return closes;
  const valid = closes.filter(c => c != null && c > 0);
  if (valid.length < 5) return closes;
  const sorted = [...valid].sort((a, b) => a - b);
  const median = sorted[Math.floor(sorted.length / 2)];
  return closes.map(c => {
    if (c == null) return c;
    if (median > 0 && c > median * 50 && c < median * 200) return +(c / 100).toFixed(4);
    return c;
  });
}

function filterMOC(raw, isIntraday) {
  if (!isIntraday || !raw) return raw;
  const idx = [];
  for (let i = 0; i < raw.timestamps.length; i++) {
    if (toCairoHour(raw.timestamps[i]) < 14) idx.push(i);
  }
  return {
    timestamps: idx.map(i => raw.timestamps[i]),
    opens:   idx.map(i => raw.opens[i]),
    highs:   idx.map(i => raw.highs[i]),
    lows:    idx.map(i => raw.lows[i]),
    closes:  idx.map(i => raw.closes[i]),
    volumes: idx.map(i => raw.volumes[i])
  };
}

function healGrid(raw, intervalSec) {
  if (!raw || raw.timestamps.length < 2) return raw;
  const healed = { timestamps: [], opens: [], highs: [], lows: [], closes: [], volumes: [] };
  for (let i = 0; i < raw.timestamps.length; i++) {
    if (i > 0) {
      const gap = raw.timestamps[i] - raw.timestamps[i - 1];
      if (gap > intervalSec * 1.5 && gap < intervalSec * 50) {
        const prevClose = healed.closes[healed.closes.length - 1] || raw.closes[i - 1];
        let fillTs = raw.timestamps[i - 1] + intervalSec;
        while (fillTs < raw.timestamps[i]) {
          const fillHour = toCairoHour(fillTs);
          if (fillHour >= 10 && fillHour < 14) {
            healed.timestamps.push(fillTs);
            healed.opens.push(prevClose); healed.highs.push(prevClose);
            healed.lows.push(prevClose); healed.closes.push(prevClose);
            healed.volumes.push(0);
          }
          fillTs += intervalSec;
        }
      }
    }
    const prevClose = healed.closes.length > 0 ? healed.closes[healed.closes.length - 1] : null;
    const c = raw.closes[i], o = raw.opens[i], h = raw.highs[i], l = raw.lows[i];
    if (c != null && c > 0) {
      healed.timestamps.push(raw.timestamps[i]);
      healed.opens.push(o != null && o > 0 ? o : c);
      healed.highs.push(h != null && h > 0 ? h : c);
      healed.lows.push(l != null && l > 0 ? l : c);
      healed.closes.push(c);
      healed.volumes.push(raw.volumes[i] || 0);
    } else if (prevClose != null) {
      healed.timestamps.push(raw.timestamps[i]);
      healed.opens.push(prevClose); healed.highs.push(prevClose);
      healed.lows.push(prevClose); healed.closes.push(prevClose);
      healed.volumes.push(0);
    }
  }
  return healed;
}

function synthesize4H(healed1H) {
  if (!healed1H || healed1H.timestamps.length < 4) return null;
  const byDay = {};
  for (let i = 0; i < healed1H.timestamps.length; i++) {
    const day = toCairoDate(healed1H.timestamps[i]);
    if (!byDay[day]) byDay[day] = [];
    byDay[day].push(i);
  }
  const result = { timestamps: [], opens: [], highs: [], lows: [], closes: [], volumes: [] };
  for (const day of Object.keys(byDay).sort()) {
    const indices = byDay[day];
    if (indices.length === 0) continue;
    const dayO = healed1H.opens[indices[0]];
    const dayH = Math.max(...indices.map(i => healed1H.highs[i]));
    const dayL = Math.min(...indices.map(i => healed1H.lows[i]));
    const dayC = healed1H.closes[indices[indices.length - 1]];
    const dayV = indices.reduce((s, i) => s + (healed1H.volumes[i] || 0), 0);
    if (dayC > 0) {
      result.timestamps.push(healed1H.timestamps[indices[0]]);
      result.opens.push(dayO); result.highs.push(dayH);
      result.lows.push(dayL); result.closes.push(dayC);
      result.volumes.push(dayV);
    }
  }
  return result.closes.length >= 5 ? result : null;
}

function toPlainOHLCV(healed) {
  if (!healed) return null;
  const fixedCloses = fixPiastreAnomaly(healed.closes);
  return {
    opens: healed.opens, highs: healed.highs,
    lows: healed.lows, closes: fixedCloses, volumes: healed.volumes
  };
}

// MAIN ORCHESTRATOR
const fetchLog = [];
const results = [];

for (const stock of stocks) {
  const bundle = {
    stock: stock.ticker, fullName: stock.name,
    runDate, currentPrice: 0, mtf: {}, error: null
  };
  let hasAnyData = false;

  for (const tf of fetchMatrix) {
    const isIntraday = (tf.id === '15m' || tf.id === '1H');
    const intervalSec = tf.id === '15m' ? 900 : tf.id === '1H' ? 3600 : 0;

    const result = await fetchYahoo(stock.ticker, tf.interval, tf.range);
    fetchLog.push({ stock: stock.ticker, tf: tf.id, ok: result.ok, err: result.err || null });

    if (result.ok) {
      let raw = extractOHLCV(result.data);
      if (raw && raw.timestamps.length > 0) {
        raw = filterMOC(raw, isIntraday);
        if (isIntraday && intervalSec > 0) raw = healGrid(raw, intervalSec);
        const plain = toPlainOHLCV(raw);
        if (plain && plain.closes.length >= 10) {
          bundle.mtf[tf.id] = plain;
          hasAnyData = true;
          const lastClose = plain.closes[plain.closes.length - 1];
          if (lastClose > 0) bundle.currentPrice = +lastClose.toFixed(2);
        }
        if (tf.id === '1H' && raw) {
          const synth4H = synthesize4H(raw);
          const plain4H = toPlainOHLCV(synth4H);
          if (plain4H && plain4H.closes.length >= 10) {
            bundle.mtf['4H'] = plain4H;
          }
        }
      }
    }
    await sleep(2000);
  }

  if (!hasAnyData) {
    bundle.error = 'No data from Yahoo Finance for ' + stock.ticker + '.CA across all timeframes.';
  } else if (!bundle.mtf['4H']) {
    bundle.error = 'Warning: Missing 4H macro anchor for ' + stock.ticker + '. Partial TA only.';
  }

  results.push({ json: bundle });
}

results.push({ json: { _fetchLog: fetchLog } });
return results;

/*
 * TA ENGINE — Multi-Timeframe + EGX Research Optimized
 *
 * EXISTING (kept): EMA, RSI-14, MACD 12/26/9, ATR, Zigzag, Elliott Wave,
 *                  Fibonacci, OBV, A/D Line, Volume Spikes, Pattern Detection
 *
 * NEW (from EGX research):
 *   - RSI Short (3-period, 85/15) — 91% win rate on EGX
 *   - MACD EGX (8/17/9) — optimized for EGX volatility
 *   - Ichimoku (7/22/44) — adapted for 5-day EGX week
 *   - MFI (14-period, 80/20) — smart money flow detection
 *   - CMF (20-period) — accumulation/distribution confirmation
 *   - ADX/DMI (14-period) — trend strength filter
 *   - Bollinger Bands (10/2.5) — volatility squeeze detection
 *   - Stochastic (9/3/2) — quick oscillator signals
 */

if ($input.all()[0]?.json?._skip) return $input.all();

const TF_HIERARCHY = ['1W', '4H', '1H', '15m'];
const TF_WEIGHTS = { '1W': 2, '4H': 5, '1H': 3, '15m': 2 };
const ZZ_THRESHOLDS = { '1W': 0.06, '4H': 0.04, '1H': 0.025, '15m': 0.015 };

// ═══ CORE INDICATORS (existing) ═══

function calcEMA(arr, p) {
  if (!arr.length) return [];
  const k = 2 / (p + 1), e = [arr[0]];
  for (let i = 1; i < arr.length; i++) e.push(arr[i] * k + e[i - 1] * (1 - k));
  return e;
}

function calcRSI(closes, p) {
  p = p || 14;
  if (closes.length < p + 2) return { value: 50, prev: 50, slope: 0 };
  const g = [], l = [];
  for (let i = 1; i < closes.length; i++) {
    const d = closes[i] - closes[i - 1];
    g.push(d > 0 ? d : 0);
    l.push(d < 0 ? -d : 0);
  }
  let ag = g.slice(0, p).reduce((a, b) => a + b, 0) / p;
  let al = l.slice(0, p).reduce((a, b) => a + b, 0) / p;
  let cur = 50, prev = 50;
  for (let i = p; i < g.length; i++) {
    ag = (ag * (p - 1) + g[i]) / p;
    al = (al * (p - 1) + l[i]) / p;
    prev = cur;
    cur = al === 0 ? 100 : 100 - 100 / (1 + ag / al);
  }
  return { value: +cur.toFixed(2), prev: +prev.toFixed(2), slope: +(cur - prev).toFixed(2) };
}

function calcMACD(closes) {
  if (closes.length < 27) return null;
  const e12 = calcEMA(closes, 12), e26 = calcEMA(closes, 26);
  const ml = e12.map((v, i) => v - e26[i]);
  const sl = calcEMA(ml, 9);
  const h = ml.map((v, i) => v - sl[i]);
  const n = ml.length;
  return {
    line: +ml[n - 1].toFixed(4), signal: +sl[n - 1].toFixed(4),
    histogram: +h[n - 1].toFixed(4),
    prevHistogram: n > 1 ? +h[n - 2].toFixed(4) : 0,
    histSlope: n > 1 ? +(h[n - 1] - h[n - 2]).toFixed(4) : 0,
    crossover: n > 1 && ml[n - 2] < sl[n - 2] && ml[n - 1] > sl[n - 1] ? 'bullish'
             : n > 1 && ml[n - 2] > sl[n - 2] && ml[n - 1] < sl[n - 1] ? 'bearish' : 'none'
  };
}

function calcATR(H, L, C, p) {
  p = p || 14;
  if (C.length < 2) return 0;
  const tr = [];
  for (let i = 1; i < C.length; i++)
    tr.push(Math.max(H[i] - L[i], Math.abs(H[i] - C[i - 1]), Math.abs(L[i] - C[i - 1])));
  if (tr.length < p) return +(tr.reduce((a, b) => a + b, 0) / tr.length).toFixed(4);
  let a = tr.slice(0, p).reduce((x, y) => x + y, 0) / p;
  for (let i = p; i < tr.length; i++) a = (a * (p - 1) + tr[i]) / p;
  return +a.toFixed(4);
}

// ═══ NEW: RSI SHORT-TERM (3-period, 85/15) ═══
function calcRSIShort(closes) {
  const p = 3;
  if (closes.length < p + 2) return { value: 50, signal: 'neutral' };
  const g = [], l = [];
  for (let i = 1; i < closes.length; i++) {
    const d = closes[i] - closes[i - 1];
    g.push(d > 0 ? d : 0);
    l.push(d < 0 ? -d : 0);
  }
  let ag = g.slice(0, p).reduce((a, b) => a + b, 0) / p;
  let al = l.slice(0, p).reduce((a, b) => a + b, 0) / p;
  let cur = 50;
  for (let i = p; i < g.length; i++) {
    ag = (ag * (p - 1) + g[i]) / p;
    al = (al * (p - 1) + l[i]) / p;
    cur = al === 0 ? 100 : 100 - 100 / (1 + ag / al);
  }
  const val = +cur.toFixed(2);
  let signal = 'neutral';
  if (val >= 85) signal = 'overbought';
  else if (val <= 15) signal = 'oversold';
  else if (val >= 70) signal = 'bullish';
  else if (val <= 30) signal = 'bearish';
  return { value: val, signal };
}

// ═══ NEW: MACD EGX-OPTIMIZED (8/17/9) ═══
function calcMACDEGX(closes) {
  if (closes.length < 18) return null;
  const e8 = calcEMA(closes, 8), e17 = calcEMA(closes, 17);
  const ml = e8.map((v, i) => v - e17[i]);
  const sl = calcEMA(ml, 9);
  const h = ml.map((v, i) => v - sl[i]);
  const n = ml.length;
  return {
    line: +ml[n-1].toFixed(4), signal: +sl[n-1].toFixed(4),
    histogram: +h[n-1].toFixed(4),
    histSlope: n > 1 ? +(h[n-1] - h[n-2]).toFixed(4) : 0,
    crossover: n > 1 && ml[n-2] < sl[n-2] && ml[n-1] > sl[n-1] ? 'bullish'
             : n > 1 && ml[n-2] > sl[n-2] && ml[n-1] < sl[n-1] ? 'bearish' : 'none'
  };
}

// ═══ NEW: ICHIMOKU (7/22/44 EGX-adapted for 5-day week) ═══
function calcIchimoku(highs, lows, closes) {
  const tenkanP = 7, kijunP = 22, senkouBP = 44;
  if (closes.length < senkouBP + 1) return null;

  function donchianMid(h, l, period, idx) {
    const start = Math.max(0, idx - period + 1);
    let hi = -Infinity, lo = Infinity;
    for (let i = start; i <= idx; i++) {
      if (h[i] > hi) hi = h[i];
      if (l[i] < lo) lo = l[i];
    }
    return (hi + lo) / 2;
  }

  const n = closes.length - 1;
  const tenkan = +donchianMid(highs, lows, tenkanP, n).toFixed(4);
  const kijun = +donchianMid(highs, lows, kijunP, n).toFixed(4);
  const senkouA = +((tenkan + kijun) / 2).toFixed(4);
  const senkouB = +donchianMid(highs, lows, senkouBP, n).toFixed(4);
  const price = closes[n];

  const cloudTop = Math.max(senkouA, senkouB);
  const cloudBot = Math.min(senkouA, senkouB);
  let cloud = 'inside_cloud';
  if (price > cloudTop) cloud = 'above_cloud';
  else if (price < cloudBot) cloud = 'below_cloud';

  const tkCross = tenkan > kijun ? 'bullish' : tenkan < kijun ? 'bearish' : 'neutral';

  return { tenkan, kijun, senkouA, senkouB, cloud, tkCross };
}

// ═══ NEW: MFI (Money Flow Index, 14-period) ═══
function calcMFI(highs, lows, closes, volumes) {
  const p = 14;
  if (closes.length < p + 1) return { value: 50, signal: 'neutral' };
  const tp = closes.map((c, i) => (highs[i] + lows[i] + c) / 3);
  let posMF = 0, negMF = 0;
  for (let i = closes.length - p; i < closes.length; i++) {
    if (i <= 0) continue;
    const mf = tp[i] * volumes[i];
    if (tp[i] > tp[i-1]) posMF += mf;
    else negMF += mf;
  }
  const mfr = negMF === 0 ? 100 : posMF / negMF;
  const val = +(100 - 100 / (1 + mfr)).toFixed(2);
  let signal = 'neutral';
  if (val >= 80) signal = 'overbought';
  else if (val <= 20) signal = 'oversold';
  return { value: val, signal };
}

// ═══ NEW: CMF (Chaikin Money Flow, 20-period) ═══
function calcCMF(highs, lows, closes, volumes) {
  const p = 20;
  if (closes.length < p) return { value: 0, signal: 'neutral' };
  let mfvSum = 0, volSum = 0;
  for (let i = closes.length - p; i < closes.length; i++) {
    const range = highs[i] - lows[i];
    if (range > 0) {
      const mfm = ((closes[i] - lows[i]) - (highs[i] - closes[i])) / range;
      mfvSum += mfm * volumes[i];
    }
    volSum += volumes[i];
  }
  const val = volSum === 0 ? 0 : +(mfvSum / volSum).toFixed(4);
  let signal = 'neutral';
  if (val > 0.05) signal = 'accumulation';
  else if (val < -0.05) signal = 'distribution';
  return { value: val, signal };
}

// ═══ NEW: ADX/DMI (14-period) ═══
function calcADX(highs, lows, closes) {
  const p = 14;
  if (closes.length < p * 2) return { adx: 0, pdi: 0, mdi: 0, signal: 'no_trend' };
  const dmP = [], dmM = [], tr = [];
  for (let i = 1; i < closes.length; i++) {
    const upMove = highs[i] - highs[i-1];
    const downMove = lows[i-1] - lows[i];
    dmP.push(upMove > downMove && upMove > 0 ? upMove : 0);
    dmM.push(downMove > upMove && downMove > 0 ? downMove : 0);
    tr.push(Math.max(highs[i] - lows[i], Math.abs(highs[i] - closes[i-1]), Math.abs(lows[i] - closes[i-1])));
  }
  let atrS = tr.slice(0, p).reduce((a, b) => a + b, 0) / p;
  let dmPS = dmP.slice(0, p).reduce((a, b) => a + b, 0) / p;
  let dmMS = dmM.slice(0, p).reduce((a, b) => a + b, 0) / p;
  const dxArr = [];
  for (let i = p; i < tr.length; i++) {
    atrS = (atrS * (p-1) + tr[i]) / p;
    dmPS = (dmPS * (p-1) + dmP[i]) / p;
    dmMS = (dmMS * (p-1) + dmM[i]) / p;
    const pdi = atrS > 0 ? (dmPS / atrS) * 100 : 0;
    const mdi = atrS > 0 ? (dmMS / atrS) * 100 : 0;
    const sum = pdi + mdi;
    dxArr.push(sum > 0 ? (Math.abs(pdi - mdi) / sum) * 100 : 0);
  }
  if (dxArr.length < p) return { adx: 0, pdi: 0, mdi: 0, signal: 'no_trend' };
  let adx = dxArr.slice(0, p).reduce((a, b) => a + b, 0) / p;
  for (let i = p; i < dxArr.length; i++) adx = (adx * (p-1) + dxArr[i]) / p;
  const lastPdi = atrS > 0 ? +(dmPS / atrS * 100).toFixed(2) : 0;
  const lastMdi = atrS > 0 ? +(dmMS / atrS * 100).toFixed(2) : 0;
  const adxVal = +adx.toFixed(2);
  let signal = 'no_trend';
  if (adxVal > 25) signal = lastPdi > lastMdi ? 'strong_uptrend' : 'strong_downtrend';
  else if (adxVal > 20) signal = lastPdi > lastMdi ? 'weak_uptrend' : 'weak_downtrend';
  else signal = 'ranging';
  return { adx: adxVal, pdi: lastPdi, mdi: lastMdi, signal };
}

// ═══ NEW: BOLLINGER BANDS (10/2.5 for EGX intraday) ═══
function calcBollinger(closes) {
  const p = 10, mult = 2.5;
  if (closes.length < p) return null;
  const slice = closes.slice(-p);
  const sma = slice.reduce((a, b) => a + b, 0) / p;
  const variance = slice.reduce((s, v) => s + Math.pow(v - sma, 2), 0) / p;
  const stdDev = Math.sqrt(variance);
  const upper = +(sma + mult * stdDev).toFixed(4);
  const lower = +(sma - mult * stdDev).toFixed(4);
  const width = +((upper - lower) / sma * 100).toFixed(2);
  const price = closes[closes.length - 1];
  const pctB = upper !== lower ? +((price - lower) / (upper - lower) * 100).toFixed(2) : 50;
  let signal = 'neutral';
  if (pctB > 100) signal = 'above_upper';
  else if (pctB < 0) signal = 'below_lower';
  else if (width < 3) signal = 'squeeze';
  return { upper, lower, middle: +sma.toFixed(4), width, pctB, signal };
}

// ═══ NEW: STOCHASTIC (9/3/2 — quick signals) ═══
function calcStochastic(highs, lows, closes) {
  const kP = 9, dP = 3, slow = 2;
  if (closes.length < kP + dP + slow) return null;
  const rawK = [];
  for (let i = kP - 1; i < closes.length; i++) {
    let hi = -Infinity, lo = Infinity;
    for (let j = i - kP + 1; j <= i; j++) {
      if (highs[j] > hi) hi = highs[j];
      if (lows[j] < lo) lo = lows[j];
    }
    const range = hi - lo;
    rawK.push(range > 0 ? ((closes[i] - lo) / range) * 100 : 50);
  }
  const slowK = [];
  for (let i = slow - 1; i < rawK.length; i++) {
    let sum = 0;
    for (let j = i - slow + 1; j <= i; j++) sum += rawK[j];
    slowK.push(sum / slow);
  }
  const dLine = [];
  for (let i = dP - 1; i < slowK.length; i++) {
    let sum = 0;
    for (let j = i - dP + 1; j <= i; j++) sum += slowK[j];
    dLine.push(sum / dP);
  }
  if (!slowK.length || !dLine.length) return null;
  const k = +slowK[slowK.length - 1].toFixed(2);
  const d = +dLine[dLine.length - 1].toFixed(2);
  const prevK = slowK.length > 1 ? +slowK[slowK.length - 2].toFixed(2) : k;
  const prevD = dLine.length > 1 ? +dLine[dLine.length - 2].toFixed(2) : d;
  let signal = 'neutral';
  if (k < 20 && d < 20) signal = 'oversold';
  else if (k > 80 && d > 80) signal = 'overbought';
  let crossover = 'none';
  if (prevK < prevD && k > d) crossover = 'bullish';
  else if (prevK > prevD && k < d) crossover = 'bearish';
  return { k, d, signal, crossover };
}

// ═══ ZIGZAG / ELLIOTT / FIBONACCI (existing, kept) ═══

function zigzag(highs, lows, threshold) {
  if (highs.length < 5) return [];
  const swings = [];
  let dir = 0, lastIdx = 0;
  while (lastIdx < highs.length && (highs[lastIdx] == null || lows[lastIdx] == null)) lastIdx++;
  if (lastIdx >= highs.length) return [];
  let lastHigh = highs[lastIdx], lastLow = lows[lastIdx];
  for (let i = lastIdx + 1; i < highs.length; i++) {
    if (highs[i] == null || lows[i] == null) continue;
    if (dir === 0) {
      if (highs[i] >= lastLow * (1 + threshold)) {
        swings.push({ idx: lastIdx, price: lastLow, type: 'L' });
        dir = 1; lastIdx = i; lastHigh = highs[i];
      } else if (lows[i] <= lastHigh * (1 - threshold)) {
        swings.push({ idx: lastIdx, price: lastHigh, type: 'H' });
        dir = -1; lastIdx = i; lastLow = lows[i];
      }
    } else if (dir === 1) {
      if (highs[i] > lastHigh) { lastIdx = i; lastHigh = highs[i]; }
      else if (lows[i] <= lastHigh * (1 - threshold)) {
        swings.push({ idx: lastIdx, price: lastHigh, type: 'H' });
        dir = -1; lastIdx = i; lastLow = lows[i];
      }
    } else {
      if (lows[i] < lastLow) { lastIdx = i; lastLow = lows[i]; }
      else if (highs[i] >= lastLow * (1 + threshold)) {
        swings.push({ idx: lastIdx, price: lastLow, type: 'L' });
        dir = 1; lastIdx = i; lastHigh = highs[i];
      }
    }
  }
  if (dir === 1) swings.push({ idx: lastIdx, price: lastHigh, type: 'H' });
  else if (dir === -1) swings.push({ idx: lastIdx, price: lastLow, type: 'L' });
  return swings;
}

function detectElliott(swings) {
  if (swings.length < 4) return { phase: 'unknown', position: 0, direction: 'none', quality: 0, label: 'N/A', waveCount: 0, subWave: null };
  const recent = swings.slice(-12);
  const lastSwing = recent[recent.length - 1];
  let startIdx = -1;
  const lookForType = lastSwing.type === 'H' ? 'L' : 'H';
  for (let i = recent.length - 2; i >= 0; i--) {
    if (recent[i].type === lookForType) {
      if (startIdx === -1) startIdx = i;
      else {
        if (lookForType === 'L' && recent[i].price < recent[startIdx].price) startIdx = i;
        else if (lookForType === 'H' && recent[i].price > recent[startIdx].price) startIdx = i;
        else break;
      }
    }
  }
  if (startIdx === -1) startIdx = 0;
  const waveSwings = recent.slice(startIdx);
  const waveCount = Math.max(0, waveSwings.length - 1);
  const direction = lastSwing.type === 'H' ? 'up' : 'down';

  let phase, position;
  if (waveCount >= 1 && waveCount <= 5) { phase = 'impulse'; position = waveCount; }
  else if (waveCount >= 6 && waveCount <= 8) { phase = 'corrective'; position = waveCount - 5; }
  else if (waveCount > 8) { phase = 'extended'; position = waveCount; }
  else { phase = 'forming'; position = 0; }

  let quality = 30;
  if (phase === 'impulse' && waveSwings.length >= 6) {
    const waveSizes = [];
    for (let i = 1; i < Math.min(waveSwings.length, 6); i++)
      waveSizes.push(Math.abs(waveSwings[i].price - waveSwings[i - 1].price));
    if (waveSizes.length >= 5) {
      const w1 = waveSizes[0], w3 = waveSizes[2], w5 = waveSizes[4];
      if (w3 >= Math.min(w1, w5)) quality += 20;
      if (w3 >= Math.max(w1, w5)) quality += 10;
    }
    if (waveSwings.length >= 3) {
      const w1Start = waveSwings[0].price, w2End = waveSwings[2].price;
      if (direction === 'up' && w2End > w1Start) quality += 15;
      else if (direction === 'down' && w2End < w1Start) quality += 15;
    }
    if (waveSwings.length >= 5) {
      const w1End = waveSwings[1].price, w4End = waveSwings[4].price;
      if (direction === 'up' && w4End > w1End * 0.98) quality += 15;
      else if (direction === 'down' && w4End < w1End * 1.02) quality += 15;
    }
    quality = Math.min(95, quality);
  } else if (phase === 'impulse' && waveCount >= 2) {
    quality = 40 + waveCount * 5;
  } else if (phase === 'corrective') {
    quality = 50;
  }

  // SUB-WAVE analysis: detect where we are within the current wave
  let subWave = null;
  if (waveSwings.length >= 4) {
    const lastWaveStart = waveSwings[waveSwings.length - 2];
    const lastWaveEnd = waveSwings[waveSwings.length - 1];
    const waveRange = Math.abs(lastWaveEnd.price - lastWaveStart.price);
    const prevWaveRange = waveSwings.length >= 3
      ? Math.abs(waveSwings[waveSwings.length - 2].price - waveSwings[waveSwings.length - 3].price) : 0;

    if (prevWaveRange > 0) {
      const ratio = +(waveRange / prevWaveRange).toFixed(2);
      let fibMatch = 'none';
      if (Math.abs(ratio - 0.618) < 0.08) fibMatch = '61.8%';
      else if (Math.abs(ratio - 0.382) < 0.08) fibMatch = '38.2%';
      else if (Math.abs(ratio - 1.618) < 0.12) fibMatch = '161.8%';
      else if (Math.abs(ratio - 1.0) < 0.08) fibMatch = '100%';
      else if (Math.abs(ratio - 2.618) < 0.15) fibMatch = '261.8%';

      subWave = { ratio, fibMatch, waveRange: +waveRange.toFixed(4) };
    }
  }

  const impulseLabels = { 1: 'W1', 2: 'W2', 3: 'W3', 4: 'W4', 5: 'W5' };
  const correctiveLabels = { 1: 'A', 2: 'B', 3: 'C' };
  const arrow = direction === 'up' ? '\u2191' : '\u2193';
  let label;
  if (phase === 'impulse') label = (impulseLabels[position] || 'W' + position) + arrow;
  else if (phase === 'corrective') label = (correctiveLabels[position] || position) + arrow;
  else label = phase + arrow;

  return { phase, position, direction, waveCount, quality, label, subWave };
}

function calcFibonacci(swings, currentPrice) {
  if (swings.length < 2 || currentPrice == null || currentPrice <= 0) return null;
  let lastHigh = null, lastLow = null;
  for (let i = swings.length - 1; i >= 0; i--) {
    if (swings[i].type === 'H' && !lastHigh && swings[i].price != null) lastHigh = swings[i];
    if (swings[i].type === 'L' && !lastLow && swings[i].price != null) lastLow = swings[i];
    if (lastHigh && lastLow) break;
  }
  if (!lastHigh || !lastLow) return null;
  const high = lastHigh.price, low = lastLow.price;
  if (high == null || low == null) return null;
  const range = high - low;
  if (range <= 0) return null;
  const isUpSwing = lastLow.idx < lastHigh.idx;
  const retRatios = [0.236, 0.382, 0.5, 0.618, 0.786];
  const extRatios = [1.272, 1.618, 2.618];
  const retracements = retRatios.map(r => +(isUpSwing ? high - range * r : low + range * r).toFixed(2));
  const extensions = extRatios.map(r => +(isUpSwing ? low + range * r : high - range * r).toFixed(2));
  const allLevels = [...retracements, ...extensions];
  let nearest = null, minDist = Infinity;
  for (const lvl of allLevels) {
    const dist = Math.abs(currentPrice - lvl);
    if (dist < minDist) { minDist = dist; nearest = lvl; }
  }
  return {
    swingHigh: +high.toFixed(2), swingLow: +low.toFixed(2),
    retracements, extensions,
    nearest: nearest ? +nearest.toFixed(2) : null,
    nearestDist: nearest ? +(minDist / currentPrice * 100).toFixed(2) : null
  };
}

// ═══ VOLUME ANALYSIS (existing + MFI/CMF) ═══

function calcOBV(closes, volumes) {
  if (closes.length < 10) return { trend: 'neutral', divergence: 'none' };
  let obv = 0;
  const obvArr = [0];
  for (let i = 1; i < closes.length; i++) {
    if (closes[i] > closes[i - 1]) obv += volumes[i];
    else if (closes[i] < closes[i - 1]) obv -= volumes[i];
    obvArr.push(obv);
  }
  const lb = Math.min(10, obvArr.length - 1);
  const obvStart = obvArr[obvArr.length - 1 - lb];
  const obvEnd = obvArr[obvArr.length - 1];
  const obvTrend = obvEnd > obvStart * 1.05 ? 'rising' : obvEnd < obvStart * 0.95 ? 'falling' : 'flat';
  const priceStart = closes[closes.length - 1 - lb];
  const priceEnd = closes[closes.length - 1];
  const priceUp = priceEnd > priceStart;
  const obvUp = obvTrend === 'rising';
  let divergence = 'none';
  if (priceUp && !obvUp) divergence = 'bearish_divergence';
  else if (!priceUp && obvUp) divergence = 'bullish_divergence';
  return { trend: obvTrend, divergence };
}

function calcADLine(highs, lows, closes, volumes) {
  if (closes.length < 10) return { trend: 'neutral' };
  let ad = 0, adPrev = 0;
  const startPrev = Math.max(0, closes.length - 11);
  for (let i = 0; i < closes.length; i++) {
    const range = highs[i] - lows[i];
    if (range > 0) {
      const mfm = ((closes[i] - lows[i]) - (highs[i] - closes[i])) / range;
      ad += mfm * volumes[i];
      if (i >= startPrev && i < closes.length - 1) adPrev += mfm * volumes[i];
    }
  }
  return { trend: ad > adPrev * 1.05 ? 'accumulation' : ad < adPrev * 0.95 ? 'distribution' : 'neutral' };
}

function detectVolumeSpikes(volumes) {
  if (volumes.length < 21) return { hasSpike: false, ratio: 1 };
  const recent = volumes.slice(-21, -1);
  const avg = recent.reduce((a, b) => a + b, 0) / recent.length;
  const lastVol = volumes[volumes.length - 1];
  const ratio = avg > 0 ? +(lastVol / avg).toFixed(2) : 1;
  return { hasSpike: ratio > 2, ratio };
}

function volumeAnalysis(highs, lows, closes, volumes) {
  const obv = calcOBV(closes, volumes);
  const ad = calcADLine(highs, lows, closes, volumes);
  const spikes = detectVolumeSpikes(volumes);
  const mfi = calcMFI(highs, lows, closes, volumes);
  const cmf = calcCMF(highs, lows, closes, volumes);

  // Enhanced smart money signal combining all volume indicators
  let smartMoney = 'neutral';
  let smConfidence = 0;

  // OBV divergence
  if (obv.divergence === 'bullish_divergence') smConfidence += 2;
  else if (obv.divergence === 'bearish_divergence') smConfidence -= 2;

  // A/D Line
  if (ad.trend === 'accumulation') smConfidence += 1;
  else if (ad.trend === 'distribution') smConfidence -= 1;

  // MFI
  if (mfi.signal === 'oversold') smConfidence += 2;
  else if (mfi.signal === 'overbought') smConfidence -= 2;

  // CMF
  if (cmf.signal === 'accumulation') smConfidence += 2;
  else if (cmf.signal === 'distribution') smConfidence -= 2;

  // Volume spike amplifies the signal
  if (spikes.hasSpike) {
    if (smConfidence > 0) smConfidence += 1;
    else if (smConfidence < 0) smConfidence -= 1;
  }

  if (smConfidence >= 4) smartMoney = 'strong_accumulation';
  else if (smConfidence >= 2) smartMoney = 'accumulation';
  else if (smConfidence <= -4) smartMoney = 'strong_distribution';
  else if (smConfidence <= -2) smartMoney = 'distribution';
  else if (spikes.hasSpike) smartMoney = 'high_activity';

  return {
    obv: obv.trend, obvDivergence: obv.divergence,
    adLine: ad.trend,
    volumeSpike: spikes.hasSpike, volumeRatio: spikes.ratio,
    mfi: mfi.value, mfiSignal: mfi.signal,
    cmf: cmf.value, cmfSignal: cmf.signal,
    smartMoney, smConfidence
  };
}

// ═══ PATTERN DETECTION (existing, kept) ═══

function detectPatterns(swings) {
  if (swings.length < 4) return { structure: 'unknown', patterns: [] };
  const patterns = [];
  const recentHighs = swings.filter(s => s.type === 'H').slice(-4).map(s => s.price);
  const recentLows = swings.filter(s => s.type === 'L').slice(-4).map(s => s.price);
  let structure = 'unknown';
  if (recentHighs.length >= 2 && recentLows.length >= 2) {
    const hh = recentHighs[recentHighs.length - 1] > recentHighs[recentHighs.length - 2];
    const hl = recentLows[recentLows.length - 1] > recentLows[recentLows.length - 2];
    const lh = recentHighs[recentHighs.length - 1] < recentHighs[recentHighs.length - 2];
    const ll = recentLows[recentLows.length - 1] < recentLows[recentLows.length - 2];
    if (hh && hl) structure = 'uptrend (HH/HL)';
    else if (lh && ll) structure = 'downtrend (LH/LL)';
    else if (hh && ll) structure = 'expanding';
    else if (lh && hl) structure = 'contracting';
    else structure = 'ranging';
  }
  if (recentLows.length >= 2) {
    const l = recentLows.slice(-2);
    if (Math.abs(l[0] - l[1]) / l[0] < 0.02) patterns.push('Double Bottom');
  }
  if (recentHighs.length >= 2) {
    const h = recentHighs.slice(-2);
    if (Math.abs(h[0] - h[1]) / h[0] < 0.02) patterns.push('Double Top');
  }
  return { structure, patterns };
}

// ═══ LEGACY S/R + MERGE (existing, kept) ═══

function calcLegacySR(H, L, C) {
  const raw = [];
  for (let i = 2; i < C.length - 2; i++) {
    if (H[i] > H[i-1] && H[i] > H[i-2] && H[i] > H[i+1] && H[i] > H[i+2]) raw.push({ price: H[i], type: 'R' });
    if (L[i] < L[i-1] && L[i] < L[i-2] && L[i] < L[i+1] && L[i] < L[i+2]) raw.push({ price: L[i], type: 'S' });
  }
  const used = new Set(), cl = [];
  for (let i = 0; i < raw.length; i++) {
    if (used.has(i)) continue;
    let sum = raw[i].price, cnt = 1;
    for (let j = i + 1; j < raw.length; j++)
      if (!used.has(j) && Math.abs(raw[j].price - raw[i].price) / raw[i].price < 0.02) {
        sum += raw[j].price; cnt++; used.add(j);
      }
    used.add(i);
    cl.push({ p: +(sum / cnt).toFixed(2), s: cnt });
  }
  cl.sort((a, b) => b.s - a.s);
  const price = C[C.length - 1];
  return {
    supports: cl.filter(x => x.p < price).sort((a, b) => b.p - a.p).slice(0, 3).map(x => x.p),
    resistances: cl.filter(x => x.p >= price).sort((a, b) => a.p - b.p).slice(0, 3).map(x => x.p)
  };
}

function mergeSR(legacy, fib, price) {
  const supports = [...(legacy?.supports || [])];
  const resistances = [...(legacy?.resistances || [])];
  if (fib) {
    for (const lvl of fib.retracements) {
      if (lvl < price && !supports.find(s => Math.abs(s - lvl) / price < 0.01)) supports.push(lvl);
      else if (lvl >= price && !resistances.find(r => Math.abs(r - lvl) / price < 0.01)) resistances.push(lvl);
    }
    for (const lvl of fib.extensions) {
      if (lvl >= price && !resistances.find(r => Math.abs(r - lvl) / price < 0.01)) resistances.push(lvl);
    }
  }
  supports.sort((a, b) => b - a);
  resistances.sort((a, b) => a - b);
  return { supports: supports.slice(0, 5), resistances: resistances.slice(0, 5) };
}

// ═══ COMPUTE ONE TIMEFRAME (expanded with all new indicators) ═══

function computeTF(ohlcv, tfId) {
  const { opens, highs, lows, closes, volumes } = ohlcv;
  if (closes.length < 20) return null;
  const n = closes.length;
  let price = closes[n - 1];
  if (price == null || price <= 0) {
    for (let i = n - 2; i >= 0; i--) { if (closes[i] != null && closes[i] > 0) { price = closes[i]; break; } }
  }
  if (price == null || price <= 0) return null;

  // Core EMAs
  const e9 = calcEMA(closes, 9), e21 = calcEMA(closes, 21);
  const e50 = calcEMA(closes, Math.min(50, closes.length));
  const ema9 = +e9[n-1].toFixed(4), ema21 = +e21[n-1].toFixed(4), ema50 = +e50[n-1].toFixed(4);
  const align = ema9 > ema21 && ema21 > ema50 ? 'bullish'
              : ema9 < ema21 && ema21 < ema50 ? 'bearish' : 'mixed';

  // RSI-14 (existing)
  const rsi = calcRSI(closes, 14);
  // RSI-3 (new — EGX optimized 91% win rate)
  const rsiShort = calcRSIShort(closes);

  // MACD standard (existing)
  const macd = calcMACD(closes);
  // MACD EGX (new — 8/17/9)
  const macdEgx = calcMACDEGX(closes);

  // ATR (existing)
  const atr = calcATR(highs, lows, closes, 14);

  // Ichimoku (new — 7/22/44)
  const ichimoku = calcIchimoku(highs, lows, closes);

  // ADX (new)
  const adx = calcADX(highs, lows, closes);

  // Bollinger (new — 10/2.5)
  const bollinger = calcBollinger(closes);

  // Stochastic (new — 9/3/2)
  const stochastic = calcStochastic(highs, lows, closes);

  // Zigzag + Elliott
  const zzThreshold = ZZ_THRESHOLDS[tfId] || 0.03;
  const swings = zigzag(highs, lows, zzThreshold);
  const elliott = detectElliott(swings);
  const fib = calcFibonacci(swings, price);
  const legacySR = calcLegacySR(highs, lows, closes);
  const mergedSR = mergeSR(legacySR, fib, price);

  // Volume analysis (enhanced with MFI/CMF)
  const vol = volumeAnalysis(highs, lows, closes, volumes);

  // Pattern detection
  const pats = detectPatterns(swings);

  return {
    ema9, ema21, ema50, emaAlign: align,
    rsi, rsiShort,
    macd, macdEgx,
    atr,
    ichimoku, adx, bollinger, stochastic,
    sr: mergedSR, elliott, fib,
    volume: vol, patterns: pats
  };
}

// ═══ CROSS-TF WAVE ALIGNMENT (existing, kept) ═══

function waveAlignment(tfs) {
  const waves = {};
  for (const [tf, data] of Object.entries(tfs)) {
    if (data?.elliott) waves[tf] = data.elliott;
  }
  const entries = Object.entries(waves);
  if (entries.length < 2) return { aligned: false, signal: 'insufficient_data', detail: '' };
  const directions = entries.map(([_, w]) => w.direction);
  const allUp = directions.every(d => d === 'up');
  const allDown = directions.every(d => d === 'down');
  const higherTF = waves['1W'] || waves['4H'];
  const lowerTF = waves['1H'] || waves['15m'];
  let signal = 'neutral';
  let detail = entries.map(([tf, w]) => tf + ':' + w.label).join(' | ');
  if (allUp) {
    signal = higherTF && higherTF.phase === 'impulse' && higherTF.position === 3
           ? 'strong_bullish_alignment' : 'bullish_alignment';
  } else if (allDown) {
    signal = higherTF && higherTF.phase === 'impulse' && higherTF.position === 3
           ? 'strong_bearish_alignment' : 'bearish_alignment';
  } else if (higherTF && lowerTF) {
    if (higherTF.direction === 'up' && lowerTF.phase === 'corrective') signal = 'pullback_in_uptrend';
    else if (higherTF.direction === 'down' && lowerTF.phase === 'corrective') signal = 'bounce_in_downtrend';
    else signal = 'divergent';
  }
  return { aligned: allUp || allDown, signal, detail };
}

// ═══ ENHANCED MTF CONFLUENCE (updated with all new indicators) ═══

function confluence(tfs, waveAlign) {
  let bull = 0, bear = 0, total = 0;
  for (const [tf, data] of Object.entries(tfs)) {
    if (!data) continue;
    const w = TF_WEIGHTS[tf] || 1;
    total += w;

    // EMA alignment (10%)
    if (data.emaAlign === 'bullish') bull += w * 0.10;
    else if (data.emaAlign === 'bearish') bear += w * 0.10;

    // RSI-14 trend (5%)
    if (data.rsi?.value > 55) bull += w * 0.05;
    else if (data.rsi?.value < 45) bear += w * 0.05;

    // RSI-3 extreme signals (8% — high weight due to 91% win rate on EGX)
    if (data.rsiShort?.signal === 'oversold') bull += w * 0.08;
    else if (data.rsiShort?.signal === 'overbought') bear += w * 0.08;

    // MACD EGX (8%)
    if (data.macdEgx) {
      if (data.macdEgx.histogram > 0 && data.macdEgx.histSlope > 0) bull += w * 0.05;
      else if (data.macdEgx.histogram < 0 && data.macdEgx.histSlope < 0) bear += w * 0.05;
      if (data.macdEgx.crossover === 'bullish') bull += w * 0.03;
      else if (data.macdEgx.crossover === 'bearish') bear += w * 0.03;
    }

    // Ichimoku (7%)
    if (data.ichimoku) {
      if (data.ichimoku.cloud === 'above_cloud') bull += w * 0.05;
      else if (data.ichimoku.cloud === 'below_cloud') bear += w * 0.05;
      if (data.ichimoku.tkCross === 'bullish') bull += w * 0.02;
      else if (data.ichimoku.tkCross === 'bearish') bear += w * 0.02;
    }

    // ADX + DMI (7%)
    if (data.adx) {
      if (data.adx.signal === 'strong_uptrend') bull += w * 0.07;
      else if (data.adx.signal === 'strong_downtrend') bear += w * 0.07;
      else if (data.adx.signal === 'weak_uptrend') bull += w * 0.03;
      else if (data.adx.signal === 'weak_downtrend') bear += w * 0.03;
    }

    // Bollinger (5%)
    if (data.bollinger) {
      if (data.bollinger.signal === 'below_lower') bull += w * 0.05;
      else if (data.bollinger.signal === 'above_upper') bear += w * 0.05;
    }

    // Stochastic (5%)
    if (data.stochastic) {
      if (data.stochastic.signal === 'oversold') bull += w * 0.03;
      else if (data.stochastic.signal === 'overbought') bear += w * 0.03;
      if (data.stochastic.crossover === 'bullish') bull += w * 0.02;
      else if (data.stochastic.crossover === 'bearish') bear += w * 0.02;
    }

    // Elliott Wave (10%)
    if (data.elliott) {
      const ew = data.elliott;
      if (ew.phase === 'impulse') {
        if (ew.direction === 'up') {
          if (ew.position === 3) bull += w * 0.10;
          else if (ew.position === 1 || ew.position === 5) bull += w * 0.06;
          else bull += w * 0.03;
        } else {
          if (ew.position === 3) bear += w * 0.10;
          else if (ew.position === 1 || ew.position === 5) bear += w * 0.06;
          else bear += w * 0.03;
        }
      } else if (ew.phase === 'corrective') {
        if (ew.direction === 'up') bear += w * 0.05;
        else bull += w * 0.05;
      }
    }

    // Smart Money / Volume (10%)
    if (data.volume) {
      if (data.volume.smartMoney === 'strong_accumulation') bull += w * 0.10;
      else if (data.volume.smartMoney === 'accumulation') bull += w * 0.06;
      else if (data.volume.smartMoney === 'strong_distribution') bear += w * 0.10;
      else if (data.volume.smartMoney === 'distribution') bear += w * 0.06;
    }

    // Patterns (5%)
    if (data.patterns?.structure) {
      if (data.patterns.structure.includes('uptrend')) bull += w * 0.05;
      else if (data.patterns.structure.includes('downtrend')) bear += w * 0.05;
      if (data.patterns.patterns?.includes('Double Bottom')) bull += w * 0.03;
      if (data.patterns.patterns?.includes('Double Top')) bear += w * 0.03;
    }
  }

  // Cross-TF wave alignment bonus (10%)
  if (waveAlign && total > 0) {
    const alignW = total * 0.10;
    if (waveAlign.signal.includes('bullish')) bull += alignW;
    else if (waveAlign.signal.includes('bearish')) bear += alignW;
    if (waveAlign.signal.includes('strong_')) {
      if (waveAlign.signal.includes('bullish')) bull += alignW * 0.5;
      else bear += alignW * 0.5;
    }
  }

  if (total === 0) return { score: 0, bias: 'neutral', strength: 'NONE' };
  const net = +((bull - bear) / total * 100).toFixed(1);
  return {
    score: net,
    bias: net > 15 ? 'bullish' : net < -15 ? 'bearish' : 'neutral',
    strength: Math.abs(net) > 50 ? 'STRONG' : Math.abs(net) > 25 ? 'MODERATE' : 'WEAK'
  };
}

