  const b5d = topBuy.ai.prediction_5d || {};
  headerLines.push('📈 **Best long:** ' + topBuy.fullName + ' — 24h: `' + Number(b24.low).toFixed(3) + '–' + Number(b24.high).toFixed(3) + '` · 5d: `' + Number(b5d.low).toFixed(3) + '–' + Number(b5d.high).toFixed(3) + ' EGP`');
} else {
